() => {
  // Look for global usage percentage
  const usageEl = document.querySelector('.usage-perc');
  const usage = usageEl ? usageEl.textContent.trim() : 'not found';
  return usage;
}

() => {
  // Find all elements that might contain usage percentage
  const allText = [];
  document.querySelectorAll('[class*="usage"], [class*="perc"], [class*="stat"]').forEach(el => {
    allText.push({ class: el.className, text: el.textContent.trim().substring(0, 100) });
  });
  return allText;
}

