() => {
  // Look at the page structure more broadly
  const body = document.body;
  // Find percentage patterns
  const allEls = document.querySelectorAll('*');
  const results = [];
  allEls.forEach(el => {
    if (el.children.length === 0 && el.textContent.match(/\d+\.\d+%/)) {
      results.push({ tag: el.tagName, class: el.className, text: el.textContent.trim() });
    }
  });
  return results.slice(0, 20);
}

